import{_ as a,o,c as r,a2 as e}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"每日签到","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/activities/daily-check-in.md","filePath":"zh-CN/rewards/activities/daily-check-in.md"}'),i={name:"rewards/activities/daily-check-in.md"};function p(l,t,n,s,d,u){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="每日签到" tabindex="-1">每日签到 <a class="header-anchor" href="#每日签到" aria-label="Permalink to &quot;每日签到&quot;">​</a></h1><p>每日签到是一项每天打卡领取任务币的功能。用户每天完成一次签到即可获得基础任务币奖励。坚持连续签到或累计签到达到一定天数，还可额外获得更丰厚的奖励。</p><h2 id="如何签到" tabindex="-1">如何签到 <a class="header-anchor" href="#如何签到" aria-label="Permalink to &quot;如何签到&quot;">​</a></h2><p>参与签到需已登录账号，且当日尚未签到。</p><p>操作步骤：</p><ol><li>进入任务中心或签到页面</li><li>点击&quot;签到&quot;按钮</li><li>系统显示签到成功并发放基础奖励任务币</li><li>若满足连续签到或累计签到条件，同时显示并发放额外奖励任务币</li></ol><p>签到成功后页面显示&quot;已签到&quot;状态，基础奖励任务币到账；若触发额外奖励，会同时显示额外奖励金额。</p><h2 id="签到状态说明" tabindex="-1">签到状态说明 <a class="header-anchor" href="#签到状态说明" aria-label="Permalink to &quot;签到状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>可签到</td><td>当前时间可以签到，今日尚未打卡</td></tr><tr><td>已签到</td><td>今日签到已完成</td></tr><tr><td>未签到</td><td>该日未完成签到（历史日期）</td></tr></tbody></table><h2 id="签到奖励计算答疑" tabindex="-1">签到奖励计算答疑 <a class="header-anchor" href="#签到奖励计算答疑" aria-label="Permalink to &quot;签到奖励计算答疑&quot;">​</a></h2><p><strong>签到是什么？有什么用？</strong></p><p>每日签到是一个每天打卡领奖励的功能。完成签到可获得任务币，任务币可用于兑换礼品或参与平台活动。坚持签到还能解锁连续/累计签到的额外奖励。</p><p><strong>如何签到？</strong></p><p>进入任务中心找到签到入口，点击&quot;签到&quot;按钮即可完成。每天只需操作一次。</p><p><strong>一天可以签到几次？</strong></p><p>每天只能签到一次。重复点击不会额外获得奖励，也不会影响已有签到记录。</p><p><strong>签到奖励多久到账？</strong></p><p>签到成功后任务币通常即时到账。若超过 24 小时仍未到账，请联系客服并提供账号信息。</p><p><strong>连续签到奖励是什么？怎么获得？</strong></p><p>连续签到奖励是指连续打卡 N 天后额外获得的任务币。只要不中断签到、每天按时打卡，达到指定天数后系统会自动发放奖励。具体奖励天数和金额以当前活动页面展示为准。</p><p><strong>我忘记签到了，连续签到记录断了怎么办？</strong></p><p>漏签后连续签到记录将会中断，重新从第 1 天开始计算。目前不支持补签或恢复之前的连续记录，建议每天定时打卡。</p><p><strong>连续签到和累计签到有什么区别？</strong></p><p>连续签到要求每天不间断打卡，中间漏一天记录清零重算，奖励基于&quot;连续打卡天数&quot;。累计签到只统计历史上签到的总天数，不要求连续，漏签不影响已累计天数，奖励基于&quot;累计总天数&quot;。两种模式取决于当前活动配置，页面上会有明确说明。</p><p><strong>签到记录在哪里查看？</strong></p><p>在签到页面或任务中心可以查看历史签到记录，包括哪些天已签到、当前连续/累计天数等信息。</p><p><strong>签到周期什么时候重置？</strong></p><p>签到周期分为&quot;每周重置&quot;和&quot;每月重置&quot;两种模式，具体以当前活动配置为准。每周模式在每周一 0 点重置，每月模式在每月 1 日 0 点重置。页面上会显示当前周期的开始和结束时间。</p><p><strong>为什么我昨天签到了，今天显示还是&quot;未签到&quot;？</strong></p><p>&quot;未签到&quot;是今日的状态，表示今天还未打卡，与昨天是否签到无关。每天零点后状态会刷新，需要重新签到才能变为&quot;已签到&quot;。如果确认今天已签到但状态异常，请联系客服处理。</p><p><strong>签到获得的任务币有过期时间吗？</strong></p><p>有。签到获得的任务币有有效期，过期后自动失效且不可找回。请在任务币账户页面或兑换商城查看各笔任务币的到期时间，建议及时使用。</p><p><strong>为什么签到按钮是灰色/点不了？</strong></p><p>可能原因：今日已签到、活动尚未开始或已结束、网络异常。请确认当前签到状态，若状态显示&quot;可签到&quot;但仍无法操作，请刷新页面或联系客服。</p><p><strong>每周额外奖励是什么？怎么领取？</strong></p><p>部分活动配置了每周完成一定次数签到可获得额外任务币奖励，达到条件后系统自动发放，无需手动领取。具体规则以当前活动页面展示为准。</p><h2 id="签到有效性与奖励限制" tabindex="-1">签到有效性与奖励限制 <a class="header-anchor" href="#签到有效性与奖励限制" aria-label="Permalink to &quot;签到有效性与奖励限制&quot;">​</a></h2><ul><li>签到时间以系统时间为准，非用户本地设备时间，跨时区用户需注意</li><li>每日零点后签到记录刷新，当日首次签到即为有效签到</li><li>连续签到模式下，漏签一天即中断，不可补签</li><li>累计签到和连续签到额外奖励不同时存在，取决于活动配置</li><li>历史签到记录不可修改</li><li>签到行为可推进任务中心中与签到相关的任务进度（如&quot;签到 N 次&quot;任务）</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',40)])])}const q=a(i,[["render",p]]);export{c as __pageData,q as default};
